const data = $input.first().json;

const cq = data.callback_query;
if (!cq) {
  return [{ json: { action: 'unknown', postId: '', chatId: '', callbackQueryId: '' } }];
}

const callbackData = cq.data || '';
const chatId = String((cq.message && cq.message.chat && cq.message.chat.id) ? cq.message.chat.id : (cq.from ? cq.from.id : ''));
const messageId = cq.message ? cq.message.message_id : null;
const callbackQueryId = cq.id || '';

var action = 'unknown';
var postId = '';

if (callbackData.indexOf('approve_') === 0) {
  action = 'approve';
  postId = callbackData.substring('approve_'.length);
} else if (callbackData.indexOf('reject_') === 0) {
  action = 'reject';
  postId = callbackData.substring('reject_'.length);
}

return [{
  json: {
    action: action,
    postId: postId,
    chatId: chatId,
    messageId: messageId,
    callbackQueryId: callbackQueryId
  }
}];

const qdrantResp = $input.first().json;
const approvalData = $('Parse Callback Data').item.json;

const point = qdrantResp.result && qdrantResp.result.points && qdrantResp.result.points[0]
  ? qdrantResp.result.points[0]
  : null;

if (!point || !point.payload || !point.payload.linkedinPost) {
  throw new Error('Post not found in Qdrant for ID: ' + approvalData.postId);
}

const payload = point.payload;

return [{
  json: {
    action: approvalData.action,
    chatId: approvalData.chatId,
    postId: approvalData.postId,
    pointId: point.id,
    linkedinPost: payload.linkedinPost,
    xPost: payload.xPost,
    url: payload.url,
    title: payload.title,
    source: payload.source
  }
}];

